USE `daojiawuxing`;

INSERT INTO `dish`(`id`,`name`,`subtitle`,`description`,`image`,`category`,`organ`,`ingredients`,`calories`,`protein`,`fat`,`carbs`,`fiber`,`antiInflammatory`,`taoistBenefits`,`cookingMethod`,`cookTime`,`difficulty`,`suitableConstitution`,`unsuitableConstitution`,`wisdomQuote`,`likes`,`favorites`,`createTime`,`updateTime`,`isDelete`) VALUES

/* ==================== 金行 (Metal) — 肺 ==================== */

(25,'银耳雪梨润肺羹','白色入肺，润燥生津','以银耳、雪梨、百合为主料，搭配枸杞调和寒性，是一道秋季润肺的经典道家甜羹。银耳胶质丰富，雪梨清甜，百合宁心，三者合用既润肺又安神，适合秋燥咳嗽、皮肤干燥、用嗓过度的人群。','https://images.unsplash.com/photo-1563330234-d86d73e3b8ae?w=1200','metal','肺','[\"银耳 30g\", \"雪梨 150g\", \"百合 20g\", \"枸杞 10g\", \"冰糖 5g\"]',110,2,0.3,26,4,'[\"银耳多糖有助于肠道菌群平衡\", \"百合中的秋水仙碱有抗炎活性\", \"低脂低钠适合慢性炎症长期食用\"]','[\"白色入肺，顺应秋令收敛之气\", \"润而不腻，适合肺燥咳嗽的清养\", \"安神宁心，帮助收敛神志\"]','1. 银耳提前泡发 2 小时，撕成小朵；2. 雪梨去皮去核切块，百合洗净；3. 银耳加足量清水小火炖 40 分钟至出胶；4. 加入雪梨、百合再炖 15 分钟；5. 出锅前 5 分钟加入枸杞和冰糖。',55,1,'[\"秋燥咳嗽\", \"皮肤干燥\", \"教师/主播等用嗓人群\"]','[\"风寒感冒初期\", \"脾胃虚寒腹泻\"]','肺者，气之本也。白色入肺，润物无声，方为真养。',87,52,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(26,'白萝卜百合清汤','顺气化痰，清润不燥','以白萝卜搭百合同煮，辅以豆腐增加植物蛋白，是一道低热量、高饱腹的金行清汤。白萝卜通气顺气、百合宁心安神、豆腐清补，整个汤体素净温和，适合晚餐轻食或久咳痰黏时饮用。','https://images.unsplash.com/photo-1516714435131-44d6b64dc6a9?w=1200','metal','肺','[\"白萝卜 150g\", \"百合 30g\", \"嫩豆腐 100g\", \"姜片 3片\", \"葱白 少许\"]',85,6,2.5,10,3,'[\"白萝卜中的芥子油有助于呼吸道抗炎\", \"百合多酚具有抗氧化作用\", \"低热量高水分有助于代谢废物排出\"]','[\"白萝卜顺气不伤正，适合利肺化痰\", \"清中有补，豆腐滋阴润燥\", \"适合秋末冬初的过渡调理\"]','1. 白萝卜去皮切滚刀块，百合掰开洗净，豆腐切块；2. 清水加姜片煮开，放入白萝卜煮 12 分钟；3. 加入百合再煮 5 分钟；4. 轻轻放入豆腐煮 3 分钟；5. 少量海盐和葱白调味。',22,1,'[\"慢性咽炎\", \"轻度痰多\", \"需要气道清爽者\"]','[\"极度阳虚畏寒\", \"胃寒反酸明显时\"]','气顺则百病不生。白萝卜之通气，非破气也，乃通气耳。',64,38,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(27,'山药杏仁养肺粥','温润补脾肺，双补金土','以山药、南杏仁、大米为粥底，百合增润，兼顾肺脾双补。山药性平，既益肺气又健脾；杏仁润肺降气；百合宁心。这道粥可作为早餐或病后恢复期的温和主食。','https://images.unsplash.com/photo-1516684732162-798a0062be99?w=1200','metal','肺','[\"铁棍山药 100g\", \"南杏仁 15g\", \"大米 50g\", \"百合 15g\", \"枸杞 10g\"]',195,5.5,4,36,4.5,'[\"杏仁中的维生素E和多酚有抗氧化抗炎作用\", \"山药多糖有免疫调节功能\", \"高纤维低升糖指数适合慢病饮食\"]','[\"肺脾双补，适合虚劳久咳的温和调养\", \"山药敛气，杏仁降气，一收一降合乎肺的气机\", \"粥体绵润，适合消化功能偏弱时食用\"]','1. 大米淘净，山药去皮切小段；2. 杏仁用温水浸泡 20 分钟去皮；3. 大米加足量水煮至开花；4. 加山药、杏仁、百合继续小火熬 20 分钟；5. 出锅前加枸杞和少许冰糖。',35,1,'[\"肺虚久咳\", \"皮肤粗糙干燥\", \"老人及病后恢复期\"]','[\"杏仁过敏者\", \"痰湿壅盛时可将杏仁减量\"]','脾为肺之母，补肺必先健脾。山药益脾肺，一举两得。',72,45,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(28,'莲藕荸荠清润汤','清热凉血，金水相生','莲藕清热凉血，荸荠生津润燥，配胡萝卜与玉米增加自然甜味。整道汤清甜不腻、无需过多调味，适合秋燥引起的口干舌燥、咽喉不适，也是雾霾天和暖气房里的日常润养佳品。','https://images.unsplash.com/photo-1547592166-23ac45744acd?w=1200','metal','肺','[\"莲藕 120g\", \"荸荠 80g\", \"胡萝卜 50g\", \"甜玉米 50g\", \"姜片 2片\"]',130,3,1,29,5,'[\"莲藕中的单宁酸有收敛抗炎作用\", \"荸荠中的荸荠英有抗菌活性\", \"低热量高纤维组合有助于肠道健康\"]','[\"金水相生，莲藕清热不伤阴\", \"清甜自然，减少对糖和调料的依赖\", \"适合秋冬暖气房的日常滋润\"]','1. 莲藕去皮切块，荸荠去皮，胡萝卜切滚刀块，玉米切段；2. 所有材料入锅加清水；3. 大火煮开后转中小火煮 25 分钟；4. 出锅前少量海盐调味或不加盐直接饮用。',28,1,'[\"口干舌燥\", \"秋燥明显\", \"室内暖气环境久居者\"]','[\"脾胃虚寒腹泻\", \"风寒感冒未愈\"]','莲出淤泥而不染，藕居水中而生清。食之可清肺胃之浊。',58,31,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

/* ==================== 木行 (Wood) — 肝 ==================== */

(29,'荠菜豆腐养肝汤','青色入肝，清解春困','荠菜为春季时令野菜，其性平而清，入肝经，搭配嫩豆腐与枸杞，构成一道清爽低脂的木行养肝汤。适合春季精神不振、眼疲劳和轻度肝火旺盛的人群。','https://images.unsplash.com/photo-1594756202469-9ff9799b2e4e?w=1200','wood','肝','[\"荠菜 100g\", \"嫩豆腐 150g\", \"枸杞 10g\", \"姜丝 少许\", \"芝麻油 2ml\"]',78,8,3,6,2.5,'[\"荠菜富含维生素K和类黄酮\", \"豆腐提供优质植物蛋白\", \"低热量高营养密度有助于肝脏代谢\"]','[\"青色入肝，荠菜清肝明目\", \"春食荠菜顺应肝木生发之气\", \"清而不寒，佐以姜丝温中护胃\"]','1. 荠菜洗净焯水 30 秒去草酸，切段；2. 嫩豆腐切小块；3. 清水加姜丝煮开，放入豆腐煮 3 分钟；4. 加荠菜和枸杞再煮 2 分钟；5. 淋几滴芝麻油和少量盐即可。',12,1,'[\"春季情绪波动\", \"眼干眼涩\", \"肝火轻旺\"]','[\"肾阳虚明显\", \"严重寒性体质\"]','春三月，此谓发陈。天地俱生，万物以荣。食青以应之。',81,47,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(30,'抹茶奇亚籽燕麦碗','木行能量，清神醒脑','以抹茶、燕麦、奇亚籽和香蕉为基础，结合植物奶调和，口感层次丰富，色泽青翠。抹茶中的茶氨酸帮助清醒而不过度兴奋，适合作为创意工作者的提神早餐或训练前轻食。','https://images.unsplash.com/photo-1511690743698-d9d85f2fbf38?w=1200','wood','肝','[\"即食燕麦 60g\", \"抹茶粉 3g\", \"香蕉 100g\", \"奇亚籽 10g\", \"燕麦奶 150ml\", \"蜂蜜 5g\"]',285,9,7,48,9,'[\"抹茶中的EGCG有强抗氧化抗炎作用\", \"奇亚籽富含ω-3脂肪酸有助于抗炎\", \"高纤维组合稳定血糖，减少炎症波动\"]','[\"抹茶提神而安神，合乎肝喜条达之性\", \"绿色食物应春气，助肝气疏泄\", \"燕麦稳定能量释放，避免情绪因血糖波动\"]','1. 燕麦与燕麦奶混合，冷藏浸泡 30 分钟或隔夜；2. 取出后加入抹茶粉搅拌均匀；3. 香蕉切片铺在表面；4. 撒上奇亚籽，淋蜂蜜即可。',35,1,'[\"脑力工作者\", \"晨间训练前\", \"需要长时间专注时\"]','[\"咖啡因敏感者可将抹茶减半\", \"肠胃虚寒者建议常温食用\"]','肝者，将军之官，谋虑出焉。抹茶清神助谋，不似咖啡之烈。',93,56,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(31,'枸杞芽拌黑木耳','木行凉拌，清肝明目','枸杞芽是春季时令芽菜，性凉入肝，搭配黑木耳和少量芝麻油凉拌，简单快手。黑木耳活血、枸杞芽清肝，一绿一黑，木水生发，适合作为午餐配菜或轻食沙拉替代。','https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=1200','wood','肝','[\"枸杞芽 120g\", \"黑木耳 50g\", \"蒜末 5g\", \"芝麻油 3ml\", \"生抽 3ml\", \"白芝麻 少许\"]',65,3.5,3,8,5,'[\"枸杞芽含甜菜碱和多酚有保肝抗炎作用\", \"黑木耳多糖有助于免疫调节\", \"生食蔬菜最大程度保留维生素C\"]','[\"芽菜蕴藏生发之气，契合木行春天之象\", \"凉拌少油少盐，轻盈而不加重脾胃负担\", \"黑木耳属水，水生木，暗合金水相生\"]','1. 黑木耳提前泡发，焯水 2 分钟捞出切丝；2. 枸杞芽洗净沥干，沸水焯 20 秒立即捞出过凉；3. 蒜末、芝麻油、生抽调成酱汁；4. 将枸杞芽和木耳拌匀，淋酱汁，撒白芝麻。',10,1,'[\"用眼过度\", \"肝火偏旺\", \"需要清爽配菜\"]','[\"腹泻期\", \"寒性体质明显时佐姜食用\"]','芽者，生之始也。食芽以应春气，助肝之生发条达。',56,29,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(32,'青柠薄荷疏肝饮','清凉舒展，解郁消闷','青柠酸而入肝，薄荷辛凉疏散，绿茶清热提神，蜂蜜调和诸味。这款饮品适合春夏情绪郁闷、口干口苦、胸胁胀满时饮用。冷泡或常温均可，不宜过冰以免伤胃。','https://images.unsplash.com/photo-1497534446932-c925b458314e?w=1200','wood','肝','[\"青柠 1个\", \"鲜薄荷叶 10g\", \"绿茶 3g\", \"蜂蜜 5g\", \"温水 300ml\"]',30,0.3,0,7,0.5,'[\"薄荷中的薄荷醇有抗炎镇痛作用\", \"绿茶多酚抗氧化抗炎\", \"青柠高维生素C降低氧化应激\"]','[\"酸入肝而能收，薄荷辛散以疏，一收一散合乎肝之性\", \"绿茶清热而不伤阴\", \"情志郁闷时饮之，有助于气机舒展\"]','1. 绿茶用 80°C 热水冲泡，浸泡 2 分钟后滤出茶汤放凉；2. 青柠切片，薄荷叶洗净拍醒；3. 茶汤中加入青柠片和薄荷叶，浸泡 5 分钟；4. 加蜂蜜调匀，常温或微凉饮用。',8,1,'[\"情绪郁闷\", \"口干口苦\", \"春夏提神醒脑\"]','[\"严重胃酸过多\", \"孕期前三个月\"]','肝喜条达而恶抑郁。薄荷之辛散，青柠之酸收，恰合肝气之张弛。',78,42,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

/* ==================== 水行 (Water) — 肾 ==================== */

(33,'黑豆黑米核桃粥','黑色入肾，藏精固本','黑豆、黑米、黑芝麻三黑汇聚，配核桃益智固精，枸杞引经。这是道家冬季养藏的代表粥品，适合精力不足、腰膝酸软、畏寒怕冷、头发早白的人群作为早餐或晚餐主食。','https://images.unsplash.com/photo-1550583724-b2692b85b5a6?w=1200','water','肾','[\"黑豆 30g\", \"黑米 40g\", \"核桃仁 15g\", \"黑芝麻 10g\", \"枸杞 10g\", \"红糖 5g\"]',280,11,9,40,7,'[\"黑豆花青素是强效天然抗氧化剂\", \"核桃富含ω-3脂肪酸有助于神经系统抗炎\", \"黑芝麻中的芝麻素有助于降低氧化应激\"]','[\"三黑入肾，顺应冬季藏精之道\", \"黑色属水，滋养先天之本\", \"核桃温补肾阳，黑芝麻滋补肾阴，阴阳双顾\"]','1. 黑豆提前浸泡 6 小时，黑米浸泡 2 小时；2. 黑豆、黑米加足量水大火煮开转小火熬 40 分钟；3. 核桃掰碎，黑芝麻碾碎；4. 加入核桃、黑芝麻、枸杞再煮 10 分钟；5. 关火前加红糖拌匀。',55,2,'[\"精力不足\", \"腰膝酸软\", \"头发早白\", \"畏寒怕冷\"]','[\"湿热体质\", \"急性上火期\", \"消化功能极弱时减量\"]','肾者，作强之官，伎巧出焉。黑色入肾，藏精所以生巧也。',121,78,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(34,'海带豆腐味噌汤','咸味入肾，软坚散结','以海带、豆腐为核心，辅以日式味噌调味，是一道低热量高营养的水行汤品。海带咸寒入肾，能软坚散结；豆腐滋阴；味噌发酵食品有助于肠道健康。适合日常清养和代谢调理。','https://images.unsplash.com/photo-1547592166-23ac45744acd?w=1200','water','肾','[\"干海带 15g\", \"嫩豆腐 120g\", \"白味噌 10g\", \"葱花 少许\", \"姜丝 少许\"]',72,7,2.8,6,2,'[\"海带中的褐藻多糖有抗炎和免疫调节作用\", \"发酵味噌有助于肠道微生态平衡\", \"低热量高矿物质有助于慢性代谢性炎症\"]','[\"海带咸入肾，软坚散结\", \"发酵食物的酵素有助于运化和吸收\", \"清淡而有深度，适合作为常规佐餐饮用\"]','1. 干海带泡发 30 分钟，洗净切条；2. 清水加姜丝煮开，放入海带煮 10 分钟；3. 豆腐切块入锅煮 3 分钟；4. 关火后将味噌用少许汤化开，再倒回锅中搅匀；5. 撒葱花即可（味噌不宜久煮）。',18,1,'[\"代谢偏慢\", \"甲状腺功能偏低\", \"日常清淡饮食\"]','[\"甲亢未控制\", \"严重水肿需限钠\"]','咸者，能软能下。海带之咸，非调味之咸，乃软坚散结之药咸。',95,61,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(35,'黑芝麻桑葚能量棒','随身补肾，小食大养','以燕麦、黑芝麻、桑葚干、核桃仁为基底，蜂蜜粘合，无油烘焙。每条约 40g，是随身携带的补肾能量零食，适合下午精力下降、健身后补充、户外徒步时随身食用。','https://images.unsplash.com/photo-1586991359975-3e530a8e2bc2?w=1200','water','肾','[\"燕麦片 30g\", \"黑芝麻 20g\", \"桑葚干 15g\", \"核桃仁 15g\", \"蜂蜜 10g\", \"椰枣 10g\"]',245,7,12,30,6,'[\"桑葚富含花青素和白藜芦醇\", \"黑芝麻木脂素有助于抗氧化抗炎\", \"核桃的ω-3脂肪酸有益神经抗炎\"]','[\"桑葚滋补肝肾阴血\", \"芝麻核桃阴阳双补\", \"小食大养，将补肾融入日常随手可得\"]','1. 燕麦和核桃仁用烤箱 150°C 烤 10 分钟出香；2. 椰枣去核切碎，桑葚干稍切；3. 蜂蜜小火加热至流动状，与所有干料混合拌匀；4. 铺入模具压实，冷藏 2 小时定型；5. 切条分装，冷藏保存。',25,2,'[\"下午精力低谷\", \"健身后补充\", \"需要随身健康零食者\"]','[\"糖尿病需注意碳水总量\", \"桑葚性微寒，脾胃虚寒者适量\"]','肾藏精，精生髓，髓充脑。黑色小食随身带，养精不在一朝一夕。',88,53,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(36,'紫菜虾皮蛋花汤','咸香温肾，快速补钙','紫菜咸寒入肾，虾皮温阳补钙，鸡蛋滋阴，是一道 10 分钟速成的水行快手汤。虽极简，却蕴含道家"少即是多"的理念。适合忙碌日的晚餐配汤或冬日早晨暖身。','https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=1200','water','肾','[\"紫菜 10g\", \"虾皮 15g\", \"鸡蛋 1个\", \"嫩豆腐 100g\", \"姜丝 5g\", \"葱花 少许\"]',120,13,4.5,6,1.5,'[\"紫菜含有藻胆蛋白有抗炎活性\", \"虾皮高钙低脂\", \"鸡蛋卵磷脂有助于神经系统健康\"]','[\"紫色属水入肾，紫菜清中有养\", \"虾皮温阳暖肾，姜丝温中防寒\", \"简单快速，合乎道家不为物累的饮食观\"]','1. 紫菜撕碎，虾皮温水略洗；2. 清水加姜丝煮开，放虾皮煮 2 分钟；3. 豆腐切小块入锅煮 2 分钟；4. 鸡蛋打散，慢慢淋入汤中形成蛋花；5. 关火后加入紫菜和葱花，少量盐和香油调味。',10,1,'[\"忙碌日快速补养\", \"钙摄入不足\", \"冬季晨起暖身\"]','[\"痛风急性期\", \"虾皮过敏者\"]','治大国若烹小鲜。一碗蛋花汤，急不得，慢不得，恰到好处即得。',73,44,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

/* ==================== 火行 (Fire) — 心 ==================== */

(37,'红豆莲子安神汤','赤色养心，安神定志','红豆补心血，莲子清心安神，桂圆红枣温养心脾，陈皮理气防滞。这道甜汤可作为午后点心或睡前一小时温饮，适合心烦失眠、心悸多梦、压力大时调理。','https://images.unsplash.com/photo-1473093295043-cdd812d0e601?w=1200','fire','心','[\"红豆 50g\", \"莲子 20g\", \"桂圆肉 10g\", \"红枣 5颗\", \"陈皮 2g\"]',210,9,1,43,8,'[\"红豆皮富含原花青素有抗氧化作用\", \"莲子中的莲心碱有镇静和心血管保护作用\", \"红枣多糖有免疫调节功能\"]','[\"赤色入心，红豆养心血\", \"莲子宁心安神，帮助收敛浮火\", \"桂圆补心脾，红枣养血，适合心脾两虚\"]','1. 红豆提前浸泡 4 小时，莲子去芯；2. 红豆加足量水煮开转小火煮 30 分钟；3. 加入莲子、红枣再煮 20 分钟；4. 加桂圆肉煮 5 分钟；5. 关火前放入陈皮丝，少量冰糖调味。',55,1,'[\"心烦失眠\", \"心悸多梦\", \"用脑过度后的心脾调理\"]','[\"腹胀明显\", \"湿热体质可去桂圆\"]','心者，君主之官，神明出焉。心神得安，则百脉皆从。',115,72,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(38,'山楂红枣消食饮','化积消滞，活血养心','山楂消食化积、活血散瘀，红枣养血安神，陈皮理气，甘草调和。适合饮食油腻后解腻消食，也适合心血瘀滞引起的胸闷不适。酸甜可口，老少皆宜。','https://images.unsplash.com/photo-1497534446932-c925b458314e?w=1200','fire','心','[\"干山楂 15g\", \"红枣 5颗\", \"陈皮 3g\", \"甘草 2g\", \"水 500ml\"]',35,0.5,0.1,8,1.5,'[\"山楂中的山楂酸有抗炎抗氧化作用\", \"陈皮中的橙皮苷有助于血管健康\", \"甘草酸有抗炎活性\"]','[\"山楂活血散瘀，心主血脉，瘀去则心血得行\", \"红枣甘温养心脾\", \"酸甘化阴，适合心阴偏虚的轻度口干\"]','1. 山楂、红枣去核、陈皮、甘草洗净；2. 所有材料加 500ml 水；3. 大火煮开后转小火煮 15 分钟；4. 滤出茶汤，可复泡一次。',18,1,'[\"饮食油腻后\", \"轻度胸闷\", \"需要助消化时\"]','[\"胃酸过多\", \"空腹时\", \"孕期\"]','山楂善消肉食之积，陈皮善化气滞之壅。心脉以通为贵。',62,35,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(39,'紫薯百合养心羹','紫赤兼收，心火得降','紫薯富含花青素，色泽紫红，兼得火行之赤与心脉之养。百合宁心安神，搭配莲子增强清心效果。这道羹品口感绵密，天然甜度即可满足口欲，适合晚间替代甜品。','https://images.unsplash.com/photo-1550583724-b2692b85b5a6?w=1200','fire','心','[\"紫薯 150g\", \"百合 20g\", \"莲子 15g\", \"牛奶 100ml\", \"蜂蜜 5g\"]',160,3.5,0.5,37,5,'[\"紫薯花青素是高效抗氧化剂\", \"百合中的甾体皂苷有抗炎活性\", \"莲子有助于降低炎症因子\"]','[\"紫红色入心，紫薯养心之阴\", \"百合宁心，莲子清心，双清配伍\", \"晚间食用有助于心神的收敛与安眠\"]','1. 紫薯去皮切块蒸 20 分钟至软烂；2. 莲子去芯，百合洗净；3. 蒸好的紫薯捣成泥；4. 莲子与百合加少量水煮 10 分钟；5. 紫薯泥与莲子百合混合，加牛奶搅匀，小火加热，出锅前加蜂蜜。',30,1,'[\"晚间替代甜品\", \"心烦不易入睡\", \"抗氧化需求高\"]','[\"血糖偏高者去蜂蜜\", \"牛奶不耐受可用燕麦奶替代\"]','五味令人口爽，圣人为腹不为目。紫薯之甘，自然之甘也。',84,55,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(40,'玫瑰花酿枸杞饮','疏肝宁心，气血双调','玫瑰花疏肝解郁，枸杞养肝明目，红枣养血安神，蜂蜜调和。这款花茶虽兼涉肝与心，但以宁心安神为最终指向——肝气舒则心气顺，适合情绪低落、胸闷叹气、睡前思绪过多时饮用。','https://images.unsplash.com/photo-1547592180-85f173990554?w=1200','fire','心','[\"干玫瑰花 10g\", \"枸杞 10g\", \"红枣 3颗\", \"蜂蜜 5g\", \"热水 400ml\"]',28,0.5,0.1,6,1,'[\"玫瑰花中的多酚和黄酮有抗炎抗氧化作用\", \"枸杞多糖调节免疫与炎症反应\", \"红枣含有环磷酸腺苷有助于心血管\"]','[\"玫瑰花疏肝则心气自畅\", \"枸杞养肝血以济心阴\", \"芳香开郁，适合情绪主导的身心调理\"]','1. 玫瑰花用温水略洗；2. 红枣去核切片，枸杞洗净；3. 玫瑰花、红枣、枸杞放入茶壶；4. 80°C 热水冲泡，焖 5 分钟；5. 稍凉后加蜂蜜调匀。',8,1,'[\"情绪低落\", \"经前烦躁\", \"睡前思绪过多\"]','[\"玫瑰花行气力较强，经期量多时暂停\", \"蜂蜜过敏者去蜂蜜\"]','上善若水，水利万物而不争。玫瑰花水，柔而不烈，解郁于无声。',104,68,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

/* ==================== 土行 (Earth) — 脾 ==================== */

(41,'茯苓薏米健脾汤','土行祛湿，轻身益气','以茯苓、薏米、山药、芡实四味药食同源食材为核心，陈皮理气，构成一道甘淡平和的土行祛湿汤。适合湿气重、身体困重、大便黏腻、舌苔厚腻的人群作为周期性清养汤品。','https://images.unsplash.com/photo-1547592166-23ac45744acd?w=1200','earth','脾','[\"茯苓 20g\", \"薏米 40g\", \"山药 100g\", \"芡实 15g\", \"陈皮 3g\"]',175,5,1.2,37,5.5,'[\"茯苓多糖有免疫调节和抗炎作用\", \"薏米中的薏苡仁酯有抗炎活性\", \"芡实有助于肠道黏膜修复\"]','[\"脾主运化水湿，此方四味皆健脾祛湿\", \"甘淡平和，久服不伤正气\", \"陈皮理气，使补而不滞\"]','1. 薏米提前浸泡 2 小时，芡实浸泡 1 小时；2. 茯苓掰小块，山药去皮切段；3. 薏米、芡实先下锅煮 20 分钟；4. 加茯苓、山药再煮 15 分钟；5. 最后 5 分钟加入陈皮，少量海盐调味。',40,1,'[\"湿气重\", \"身体困重\", \"大便黏腻\", \"久坐少动\"]','[\"阴虚火旺\", \"便秘严重者减薏米量\"]','脾为后天之本，气血生化之源。湿去则脾运，脾运则气自生。',98,63,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(42,'小米南瓜黄金粥','黄色入脾，温养中焦','小米和胃温中，南瓜甘温补脾，红枣枸杞增色养气。这是道家最基础的土行早餐粥——色泽金黄，呼应五行中土之正色。适合脾胃虚弱、食欲不振、术后恢复和老人儿童日常食用。','https://images.unsplash.com/photo-1516684732162-798a0062be99?w=1200','earth','脾','[\"小米 60g\", \"南瓜 150g\", \"红枣 5颗\", \"枸杞 10g\", \"红糖 3g\"]',195,5.5,2,40,5,'[\"小米富含B族维生素有助于能量代谢\", \"南瓜中的β-胡萝卜素和果胶有抗炎作用\", \"红枣含有天然抗炎成分\"]','[\"黄色属土入脾，此粥色味皆应中土\", \"小米养胃，南瓜温脾，温而不燥\", \"适合作为日常早餐基础，建立稳定节律\"]','1. 小米淘净，南瓜去皮切小块；2. 小米加足量水大火煮开；3. 加入南瓜块和红枣转小火熬 20 分钟；4. 期间搅拌防止粘底；5. 出锅前加枸杞和少量红糖。',25,1,'[\"脾胃虚弱\", \"食欲不振\", \"老人儿童日常\", \"术后恢复期\"]','[\"糖尿病需注意用量并去红糖\", \"胃热反酸者少食\"]','五谷为养，五果为助。小米之养胃，乃天地间最朴素的供养。',132,85,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(43,'芡实莲子养胃糊','土行温补，固涩养胃','芡实、莲子、山药、茯苓、小米五味研磨成糊，温补脾胃，固涩精气。这道糊品口感细腻绵密，入口即化，适合消化能力弱、胃寒胃痛、容易腹泻的人群作为早餐或加餐。','https://images.unsplash.com/photo-1563330234-d86d73e3b8ae?w=1200','earth','脾','[\"芡实 30g\", \"莲子 20g\", \"山药 50g\", \"茯苓 15g\", \"小米 30g\"]',220,7,2,45,6,'[\"芡实中的多酚有抗氧化抗炎作用\", \"莲子有助于减少肠道炎症\", \"茯苓多糖调节免疫功能\"]','[\"芡实固涩而不滞，莲子补而不燥\", \"五谷为养，此糊集合土行精华\", \"适合作为脾虚泄泻时的温和食疗\"]','1. 芡实、莲子提前浸泡 2 小时；2. 所有材料沥干放入破壁机；3. 加 600ml 清水；4. 选择米糊模式自动完成；5. 倒出后可根据口味加少量蜂蜜或盐。',30,1,'[\"消化能力弱\", \"胃寒胃痛\", \"容易腹泻\", \"老人和幼儿\"]','[\"便秘者\", \"实热积滞\", \"腹胀严重时\"]','上工治未病。一碗养胃糊，日日行之，脾胃自固，不待病而后医。',107,66,'2026-05-07 10:00:00','2026-05-07 10:00:00',0),

(44,'四神养脾汤','四神合璧，健脾固本','四神汤源自中医经典方，以山药、莲子、茯苓、芡实四味药食同源食材配伍，是健脾祛湿、固涩精气的代表性汤方。此版本加入少量排骨增加滋味和蛋白质，亦可用纯素版本仅四味药材同煮。','https://images.unsplash.com/photo-1516714435131-44d6b64dc6a9?w=1200','earth','脾','[\"山药 80g\", \"莲子 30g\", \"茯苓 20g\", \"芡实 20g\", \"排骨 100g\", \"姜片 3片\"]',185,12,6,20,3.5,'[\"四味药食同源食材协同发挥抗炎作用\", \"排骨提供胶原蛋白和谷氨酰胺有利于肠道修复\", \"低加工、全食材理念符合抗炎饮食原则\"]','[\"四神汤是道家健脾经典，四味平和而效宏\", \"山药补脾阴，茯苓利脾湿，莲子固脾精，芡实涩脾脱\", \"适合作为每周 2 次的周期性脾土养护\"]','1. 排骨焯水去血沫；2. 莲子去芯，芡实提前浸泡 1 小时，茯苓掰小块；3. 所有材料加足量水入锅；4. 大火煮开转小火炖 1 小时；5. 最后少量海盐调味。纯素版可去排骨，四味药材加 2 片姜直接炖 30 分钟。',65,2,'[\"脾胃虚弱\", \"湿气重\", \"精力不足\", \"需要周期性调理\"]','[\"急性感染发热期\", \"便秘严重者减少芡实量\"]','四神者，非神也，取其效如神耳。健脾不在多，贵在持之以恒。',146,94,'2026-05-07 10:00:00','2026-05-07 10:00:00',0);
